-- Ferreira & Sa — Migracao Pipeline Comercial
-- Insere 629 clientes em clients + pipeline_leads
-- Tabelas: clients (name, phone, notes) + pipeline_leads (stage, case_type, etc)
-- ================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ================================================================
-- PASSO 1: Inserir 629 clientes na tabela clients
-- Usa INSERT IGNORE para evitar duplicatas por nome+telefone
-- ================================================================



























-- ================================================================
-- PASSO 2: Inserir 629 leads em pipeline_leads
-- Vincula ao client_id pelo nome (JOIN com clients)
-- ================================================================



























-- ================================================================
-- PASSO 3: VERIFICACAO FINAL
-- ================================================================

SELECT stage, COUNT(*) as qtd
FROM pipeline_leads
GROUP BY stage
ORDER BY qtd DESC;

